content:
title:
    Understanding Tens and Ones

years:
    1

difficulty:
    easy

introduction:
    In this activity, we will learn about the place value of numbers, focusing on tens and ones.

worked_example:
    {
  "example_number": 1,
  "steps": [
    "Identify the number, for example, 23.",
    "Break it down into tens and ones: 20 (2 tens) and 3 (3 ones)."
  ]
}

parameters:
    {
  "a": {
    "type": "int",
    "min": 10,
    "max": 99
  }
}

question:
    {
  "text": "What is the number of tens in {{ a }}?"
}

answers:
    [
  {
    "int": "{{ a }} / 10",
    "correct": true
  },
  {
    "int": "{{ a }} % 10",
    "correct": false
  },
  {
    "int": "{{ a }} - 10",
    "correct": false
  },
  {
    "int": "10",
    "correct": false
  }
]

solution:
    {
  "text": "The number of tens in {{ a }} is {{ a }} / 10."
}

diagram:
    {
  "type": "none",
  "elements": []
}

validation:
    {
  "required_fields": [
    "question.text",
    "answers",
    "solution.text"
  ],
  "rules": [
    {
      "check": "a != 0",
      "message": "Coefficient 'a' must not be zero."
    }
  ]
}

