title:
    Understanding Speed

years:
    7

difficulty:
    easy

introduction:
    This exercise focuses on understanding the concept of speed as a rate.

worked_example:
    {
  "example_number": 1,
  "steps": [
    "Identify the distance and time.",
    "Use the formula speed = distance / time."
  ]
}

parameters:
    {
  "distance": {
    "type": "int",
    "min": 10,
    "max": 100
  },
  "time": {
    "type": "int",
    "min": 4,
    "max": 10
  }
}

question:
    {
  "text": "If a car travels a distance of {{ distance }} km in {{ time }} hours, what is its speed in km/h?"
}

answers:
    [
  {
    "dec_1": "{{ distance }} / {{ time }}",
    "correct": true
  },
  {
    "int": "{{ distance }}",
    "correct": false
  },
  {
    "int": "{{ time }}",
    "correct": false
  },
  {
    "int": "{{ distance }} * {{ time }}",
    "correct": false
  }
]

solution:
    {
  "text": "To find the speed, use the formula: speed = distance / time. Thus, speed = {{ distance }} / {{ time }}."
}

