title:
    Calculating Final Price After Multiple Discounts

years:
    7

difficulty:
    medium

introduction:
    In this exercise, we will calculate the final price after applying multiple discounts.

worked_example:
    {
  "example_number": 1,
  "steps": [
    "Identify the original price and the discount percentages.",
    "Calculate the final price after applying each discount sequentially."
  ]
}

parameters:
    {
  "original_price": {
    "type": "float",
    "min": 50,
    "max": 500
  },
  "first_discount": {
    "type": "float",
    "min": 5,
    "max": 30
  },
  "second_discount": {
    "type": "float",
    "min": 5,
    "max": 30
  }
}

question:
    {
  "text": "If the original price is {{ original_price }} dollars, and you apply a first discount of {{ first_discount }}% followed by a second discount of {{ second_discount }}%, what is the final price?"
}

answers:
    [
  {
    "int": "{{ original_price * (1 - first_discount / 100 ) * (1 - second_discount / 100)}}",
    "correct": true
  },
  {
    "int": "{{ original_price }} - {{ first_discount }} - {{ second_discount }}",
    "correct": false
  },
  {
    "int": "{{ original_price * (1 -  first_discount / 100) + (1 - second_discount / 100}})",
    "correct": false
  },

]

solution:
    {
  "text": "The final price is {{ original_price }} * (1 - \tfrac{{ first_discount }}{100}) * (1 - \tfrac{{ second_discount }}{100}) = {{ original_price * (1 - first_discount / 100) * (1 - second_discount / 100) }} dollars."
}

