years:
    7

difficulty:
    hard

introduction:
    In this exercise, we will calculate the net profit margin of a business.

worked_example:
    {
  "example_number": 1,
  "steps": [
    "Identify the total revenue and total expenses.",
    "Use the formula: Net Profit Margin = \tfrac{Total Revenue - Total Expenses}{Total Revenue}."
  ]
}

parameters:
    {
  "total_revenue": {
    "type": "float",
    "min": 1000,
    "max": 50000
  },
  "total_expenses": {
    "type": "float",
    "min": 500,
    "max": 40000
  }
}

question:
    {
  "text": "If the total revenue is {{ total_revenue }} dollars and the total expenses are {{ total_expenses }} dollars, what is the net profit margin?"
}

answers:
    [
  {
    "dec_2": "{{ total_revenue /(total_revenue - total_expenses)}}",
    "correct": true
  },
  {
    "int": "{{ total_revenue }} - {{ total_expenses }}",
    "correct": false
  },
  {
    "int": "{{ total_expenses }} / {{ total_revenue }}",
    "correct": false
  },
  {
    "int": "{{ total_revenue }} + {{ total_expenses }}",
    "correct": false
  }
]

solution:
    {
  "text": "The net profit margin is \tfrac{{ total_revenue - total_expenses }}{total_revenue} = {{ (total_revenue - total_expenses) / total_revenue }}."
}

