  "required_fields": [
    "question.text",
    "answers",
    "solution.text"
  ],
  "rules": [
    {
      "check": "a != 0",
      "message": "Coefficient 'a' must not be zero."
    }
  ]
}

title:
    Combining Complex Terms

years:
    7

difficulty:
    hard

parameters:
    {
  "a": {
    "min": 2,
    "max": 5
  },
  "b": {
    "min": 3,
    "max": 6
  },
  "c": {
    "min": 1,
    "max": 3
  }
}

question:
    {
  "text": "Simplify the expression: {{ a }}x - {{ b }}y + {{ c }}x - {{ c }}y"
}

answers:
    [
  {
    "text": "{{ (a + c) }}x - {{ (b + c) }}y",
    "correct": true
  },
  {
    "text": "{{ a - b }}x + {{ c }}y",
    "correct": false
  },
  {
    "text": "{{ a }}x - {{ b }}",
    "correct": false
  },
  {
    "text": "{{ a + b }}x - {{ c }}y",
    "correct": false
  }
]

solution:
    {
  "text": "To simplify, combine like terms: {{ a }}x + {{ c }}x - {{ b }}y - {{ c }}y = {{ (a + c) }}x - {{ (b + c) }}y."
}

diagram:
    {
  "type": "none",
  "elements": []
}

validation:
    {
  "required_fields": [
    "question.text",
    "answers",
    "solution.text"
  ],
  "rules": [
    {
      "check": "a != 0",
      "message": "Coefficient 'a' must not be zero."
    }
  ]
}
